fun SettingsScreen(onBack: () -> Unit) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val snackbarHostState = remember { SnackbarHostState() }
    val settingsStore = remember { SettingsStore(context) }
    val apiClient = remember { ApiClient() }

    val savedApiUrl by settingsStore.apiUrl.collectAsState(initial = "")
    val savedToken by settingsStore.jwtToken.collectAsState(initial = "")

    var apiUrl by remember(savedApiUrl) { mutableStateOf(savedApiUrl) }
    var token by remember(savedToken) { mutableStateOf(savedToken) }
    var isTesting by remember { mutableStateOf(false) }

