        topBar = {
            TopAppBar(
                title = { Text("Settings") },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                },
            )
        },
        snackbarHost = { SnackbarHost(snackbarHostState) },
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(24.dp),
        ) {
            Text(
                text = "API Configuration",
                style = MaterialTheme.typography.titleMedium,
            )

            Spacer(modifier = Modifier.height(16.dp))

            OutlinedTextField(
                value = apiUrl,
                onValueChange = { apiUrl = it },
                label = { Text("API URL") },
                placeholder = { Text("https://your-server.example.com") },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
            )

            Spacer(modifier = Modifier.height(16.dp))

            OutlinedTextField(
                value = token,
                onValueChange = { token = it },
                label = { Text("JWT Token") },
                placeholder = { Text("Paste token from web app") },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
                visualTransformation = PasswordVisualTransformation(),
            )

            Spacer(modifier = Modifier.height(24.dp))

            Button(
                onClick = {
                    scope.launch {
                        settingsStore.setApiUrl(apiUrl)
                        settingsStore.setJwtToken(token)
                        snackbarHostState.showSnackbar("Settings saved")
                    }
                },
                modifier = Modifier.fillMaxWidth(),
            ) {
                Text("Save")
            }

            Spacer(modifier = Modifier.height(12.dp))

            Button(
                onClick = {
                    if (apiUrl.isBlank()) {
                        scope.launch { snackbarHostState.showSnackbar("Enter an API URL first") }
                        return@Button
                    }
                    isTesting = true
                    scope.launch {
                        val ok = withContext(Dispatchers.IO) {
                            apiClient.testConnection(apiUrl)
                        }
                        isTesting = false
                        snackbarHostState.showSnackbar(
                            if (ok) "Connection successful!" else "Connection failed"
                        )
                    }
                },
                modifier = Modifier.fillMaxWidth(),
                enabled = !isTesting,
            ) {
                if (isTesting) {
                    CircularProgressIndicator(
                        modifier = Modifier.height(20.dp),
                        strokeWidth = 2.dp,
                    )
                } else {
                    Text("Test Connection")
                }
            }

            Spacer(modifier = Modifier.height(24.dp))

            Text(
                text = "Get your JWT token from the Flotsam web app under your account settings.",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant,
            )
        }
    }
}
