}","new_string":"// Search performs hybrid full-text + semantic search. When an embedder is
// configured, it embeds the query and combines cosine similarity with FTS
// ranking. Falls back to FTS-only if no embedder or if embedding fails.
func (s *Service) Search(ctx context.Context, ownerID uuid.UUID, query string, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
	if query == "" {
		return &SearchResult{Items: []*Item{}}, nil
	}
	limit = clampLimit(limit, maxLimit)

	// Try hybrid search if embedder is available
	if s.embedder != nil {
		queryVec, err := s.embedder.Embed(ctx, query)
		if err != nil {
			slog.WarnContext(ctx, "item: search: embedding query failed, falling back to FTS",
				"error", err,
			)
		} else {
			return s.hybridSearch(ctx, ownerID, query, queryVec, filter, limit, threshold)
		}
	}

	return s.ftsSearch(ctx, ownerID, query, filter, limit)
}

// ftsSearch performs full-text search only using the search_vector column.
func (s *Service) ftsSearch(ctx context.Context, ownerID uuid.UUID, query string, filter *Filter, limit int) (*SearchResult, error) {
	qb := &queryBuilder{}
	qb.add("owner_id = $%d", ownerID)
	qb.add("search_vector @@ plainto_tsquery('english', $%d)", query)
	applyFilter(qb, filter)
	whereClause := qb.where()

	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
	var total int
	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
		return nil, fmt.Errorf("item: search count: %w", err)
	}

	dataQuery := fmt.Sprintf(
		`SELECT %s FROM items %s ORDER BY ts_rank(search_vector, plainto_tsquery('english', $2)) DESC LIMIT $%d`,
		itemColumns, whereClause, qb.nextParam())
	qb.args = append(qb.args, limit)

	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
	if err != nil {
		return nil, fmt.Errorf("item: search query: %w", err)
	}
	defer rows.Close()

	items, err := scanItems(rows)
	if err != nil {
		return nil, fmt.Errorf("item: search scan: %w", err)
	}

	return &SearchResult{
		Items:   items,
		Total:   total,
		HasMore: len(items) < total,
	}, nil
}

// hybridSearch combines FTS and semantic similarity. Items match if they pass
// either FTS or cosine similarity above the threshold. Results are ranked by
// cosine similarity with a 1.2x boost when FTS also matches.
func (s *Service) hybridSearch(ctx context.Context, ownerID uuid.UUID, query string, queryVec []float32, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
	if threshold <= 0 {
		threshold = defaultSemanticThreshold
	}

	qb := &queryBuilder{}
	qb.add("owner_id = $%d", ownerID)

	// $2 = query text, $3 = query vector, $4 = threshold
	queryParamIdx := qb.nextParam()
	qb.args = append(qb.args, query)
	vecParamIdx := qb.nextParam()
	qb.args = append(qb.args, pgvector.NewVector(queryVec))
	threshParamIdx := qb.nextParam()
	qb.args = append(qb.args, threshold)

	// Match on FTS OR semantic similarity
	matchCond := fmt.Sprintf(
		`(search_vector @@ plainto_tsquery('english', $%d) OR (embedding IS NOT NULL AND 1 - (embedding <=> $%d::vector) > $%d))`,
		queryParamIdx, vecParamIdx, threshParamIdx)
	qb.conditions = append(qb.conditions, matchCond)

	applyFilter(qb, filter)
	whereClause := qb.where()

	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
	var total int
	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
		return nil, fmt.Errorf("item: hybrid search count: %w", err)
	}

	// Rank: cosine similarity (boosted 1.2x when FTS also matches), fallback to FTS rank
	orderExpr := fmt.Sprintf(
		`CASE WHEN embedding IS NOT NULL THEN
			(1 - (embedding <=> $%d::vector)) *
			CASE WHEN search_vector @@ plainto_tsquery('english', $%d) THEN 1.2 ELSE 1.0 END
		ELSE
			ts_rank(search_vector, plainto_tsquery('english', $%d)) * 0.5
		END DESC`,
		vecParamIdx, queryParamIdx, queryParamIdx)

	limitParamIdx := qb.nextParam()
	qb.args = append(qb.args, limit)

	dataQuery := fmt.Sprintf(
		`SELECT %s FROM items %s ORDER BY %s LIMIT $%d`,
		itemColumns, whereClause, orderExpr, limitParamIdx)

	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
	if err != nil {
		return nil, fmt.Errorf("item: hybrid search query: %w", err)
	}
	defer rows.Close()

	items, err := scanItems(rows)
	if err != nil {
		return nil, fmt.Errorf("item: hybrid search scan: %w", err)
	}

	return &SearchResult{
		Items:   items,
		Total:   total,
		HasMore: len(items) < total,
	}, nil
